def collect_safety_fta_evidence(
    incident_id: str,
    incident_start: str,
    incident_end: str,
    sample_inputs: list[str],
) -> dict:
    """Collect evidence for each fault tree node."""
    return {
        "filter_config_at_incident_time": get_filter_config_snapshot(incident_start),
        "filter_audit_log": get_filter_audit_log(incident_start, incident_end),
        "safety_filter_decisions": [
            {
                "input": inp,
                "input_filter_result": replay_input_filter(inp, incident_start),
                "llm_output": replay_llm(inp, incident_start),  # if reproducible
                "output_filter_result": replay_output_filter(inp, incident_start),
            }
            for inp in sample_inputs
        ],
        "confidence_threshold_history": get_threshold_change_log(),
        "performance_test_schedule": get_perf_test_log(incident_start),
    }

from datetime import datetime, timedelta

def get_changes_before_incident(
    incident_start: datetime,
    lookback_hours: int = 48,
    systems: list[str] | None = None,
) -> dict:
    """Collect all changes in the lookback window before the incident."""
    window_start = incident_start - timedelta(hours=lookback_hours)
    systems = systems or ["app", "infra", "model", "prompt", "rag"]

    changes = {}
    if "app" in systems:
        changes["deployments"] = deployment_log.query(
            start=window_start, end=incident_start
        )
    if "infra" in systems:
        changes["helm_diffs"] = helm_audit.query(
            start=window_start, end=incident_start
        )
        changes["k8s_config"] = k8s_audit.query(
            start=window_start, end=incident_start, resource_types=["ConfigMap", "Deployment"]
        )
    if "model" in systems:
        changes["model_version_changes"] = model_registry.get_version_changes(
            start=window_start, end=incident_start
        )
    if "prompt" in systems:
        changes["prompt_template_changes"] = git_log(
            path="prompts/", start=window_start, end=incident_start
        )
    if "rag" in systems:
        changes["vector_store_updates"] = vector_store.get_update_log(
            start=window_start, end=incident_start
        )
        changes["embedding_model_changes"] = embedding_registry.get_version_changes(
            start=window_start, end=incident_start
        )
    return changes
